onDestroy(() => {
		window.removeEventListener('keydown', handleKeyDown);
		window.removeEventListener('resize', handleResize);
		if (audioCtx) audioCtx.close();
	});

	// ═══════════════════════════════════════════════════════════════════════════
	// ADVANCED SYNTHESIZER - Multi-oscillator with LFO and Modulation
	// ═══════════════════════════════════════════════════════════════════════════
	class AdvancedSynth {
		constructor(audioCtx, destination) {
			this.audioCtx = audioCtx;
			this.destination = destination;

			// Main oscillators
			this.osc1 = null;
			this.osc2 = null;
			this.osc3 = null;

			// LFO for modulation
			this.lfo = audioCtx.createOscillator();
			this.lfoGain = audioCtx.createGain();
			this.lfo.frequency.setValueAtTime(1, audioCtx.currentTime);
			this.lfoGain.gain.setValueAtTime(0, audioCtx.currentTime);
			this.lfo.connect(this.lfoGain);
			this.lfo.start();

			// Filter with envelope
			this.filter = audioCtx.createBiquadFilter();
			this.filter.type = 'lowpass';
			this.filter.frequency.setValueAtTime(2000, audioCtx.currentTime);
			this.filter.Q.setValueAtTime(1, audioCtx.currentTime);

			// Amplitude envelope
			this.ampEnvelope = audioCtx.createGain();
			this.ampEnvelope.gain.setValueAtTime(0, audioCtx.currentTime);

			// Filter envelope
			this.filterEnvelope = audioCtx.createGain();
			this.filterEnvelope.gain.setValueAtTime(0, audioCtx.currentTime);

			// Connect LFO to filter
			this.lfoGain.connect(this.filter.frequency);

			// Connect filter to amp to destination
			this.filter.connect(this.ampEnvelope);
			this.ampEnvelope.connect(destination);

			// Parameters
			this.osc1Type = 'sawtooth';
			this.osc2Type = 'sawtooth';
			this.osc3Type = 'sine';
			this.osc1Detune = 0;
			this.osc2Detune = 7;
			this.osc3Detune = -7;
			this.osc1Level = 0.5;
			this.osc2Level = 0.3;
			this.osc3Level = 0.2;
			this.filterAttack = 0.01;
			this.filterDecay = 0.2;
			this.filterSustain = 0.5;
			this.filterRelease = 0.3;
			this.ampAttack = 0.01;
			this.ampDecay = 0.1;
			this.ampSustain = 0.7;
			this.ampRelease = 0.3;
			this.lfoRate = 1;
			this.lfoDepth = 0;
			this.pitch = 440;
		}

		trigger(note, velocity = 0.8) {
			const now = this.audioCtx.currentTime;
			const freq = this.pitch * Math.pow(2, note / 12);

			// Create oscillators
			this.osc1 = this.audioCtx.createOscillator();
			this.osc2 = this.audioCtx.createOscillator();
			this.osc3 = this.audioCtx.createOscillator();

			this.osc1.type = this.osc1Type;
			this.osc2.type = this.osc2Type;
			this.osc3.type = this.osc3Type;

			this.osc1.frequency.setValueAtTime(freq, now);
			this.osc2.frequency.setValueAtTime(freq, now);
			this.osc3.frequency.setValueAtTime(freq, now);

			this.osc1.detune.setValueAtTime(this.osc1Detune, now);
			this.osc2.detune.setValueAtTime(this.osc2Detune, now);
			this.osc3.detune.setValueAtTime(this.osc3Detune, now);

			// Create gains for each oscillator
			const gain1 = this.audioCtx.createGain();
			const gain2 = this.audioCtx.createGain();
			const gain3 = this.audioCtx.createGain();

			gain1.gain.setValueAtTime(this.osc1Level * velocity, now);
			gain2.gain.setValueAtTime(this.osc2Level * velocity, now);
			gain3.gain.setValueAtTime(this.osc3Level * velocity, now);

			// Connect oscillators
			this.osc1.connect(gain1);
			this.osc2.connect(gain2);
			this.osc3.connect(gain3);

			gain1.connect(this.filter);
			gain2.connect(this.filter);
			gain3.connect(this.filter);

			// Amplitude envelope
			this.ampEnvelope.gain.cancelScheduledValues(now);
			this.ampEnvelope.gain.setValueAtTime(0, now);
			this.ampEnvelope.gain.linearRampToValueAtTime(velocity, now + this.ampAttack);
			this.ampEnvelope.gain.linearRampToValueAtTime(velocity * this.ampSustain, now + this.ampAttack + this.ampDecay);

			// Filter envelope
			this.filterEnvelope.gain.cancelScheduledValues(now);
			this.filterEnvelope.gain.setValueAtTime(0, now);
			this.filterEnvelope.gain.linearRampToValueAtTime(1000, now + this.filterAttack);
			this.filterEnvelope.gain.linearRampToValueAtTime(1000 * this.filterSustain, now + this.filterAttack + this.filterDecay);
			this.lfoGain.gain.setValueAtTime(this.lfoDepth * 500, now);

			// Start oscillators
			this.osc1.start(now);
			this.osc2.start(now);
			this.osc3.start(now);

			this.activeOscillators = [this.osc1, this.osc2, this.osc3];
			this.activeGains = [gain1, gain2, gain3];
			this.startTime = now;
		}

		release() {
			if (!this.activeOscillators) return;

			const now = this.audioCtx.currentTime;
			const releaseTime = this.ampRelease;

			this.ampEnvelope.gain.cancelScheduledValues(now);
			this.ampEnvelope.gain.setValueAtTime(this.ampEnvelope.gain.value, now);
			this.ampEnvelope.gain.linearRampToValueAtTime(0, now + releaseTime);

			this.lfoGain.gain.setValueAtTime(0, now);

			this.activeOscillators.forEach((osc, i) => {
				setTimeout(() => osc.stop(), releaseTime * 1000);
			});
		}

		setOsc1Type(type) { this.osc1Type = type; }
		setOsc2Type(type) { this.osc2Type = type; }
		setOsc3Type(type) { this.osc3Type = type; }
		setDetune(osc, detune) {
			if (osc === 1) this.osc1Detune = detune;
			if (osc === 2) this.osc2Detune = detune;
			if (osc === 3) this.osc3Detune = detune;
		}
		setLevel(osc, level) {
			if (osc === 1) this.osc1Level = level;
			if (osc === 2) this.osc2Level = level;
			if (osc === 3) this.osc3Level = level;
		}
		setLFO(rate, depth) {
			this.lfoRate = rate;
			this.lfoDepth = depth;
			this.lfo.frequency.setValueAtTime(rate, this.audioCtx.currentTime);
		}
		setFilter(freq, q) {
			this.filter.frequency.setValueAtTime(freq, this.audioCtx.currentTime);
			this.filter.Q.setValueAtTime(q, this.audioCtx.currentTime);
		}
	}

	// ═══════════════════════════════════════════════════════════════════════════
	// FLANGER EFFECT
	// ═══════════════════════════════════════════════════════════════════════════
	class Flanger {
		constructor(audioCtx, destination) {
			this.audioCtx = audioCtx;
			this.destination = destination;

			this.input = audioCtx.createGain();
			this.output = audioCtx.createGain();

			// Delay for flanging
			this.delay = audioCtx.createDelay(1);
			this.delayTime = 0.02;
			this.delay.delayTime.setValueAtTime(this.delayTime, audioCtx.currentTime);

			// LFO for modulation
			this.lfo = audioCtx.createOscillator();
			this.lfoGain = audioCtx.createGain();
			this.lfo.type = 'sine';
			this.lfo.frequency.setValueAtTime(0.5, audioCtx.currentTime);
			this.lfoGain.gain.setValueAtTime(0.01, audioCtx.currentTime);

			// Feedback
			this.feedback = audioCtx.createGain();
			this.feedback.gain.setValueAtTime(0.5, audioCtx.currentTime);

			// Connect
			this.lfo.connect(this.lfoGain);
			this.lfoGain.connect(this.delay.delayTime);

			this.input.connect(this.delay);
			this.delay.connect(this.feedback);
			this.feedback.connect(this.delay);
			this.delay.connect(this.output);
			this.input.connect(this.output);

			this.output.connect(destination);

			this.lfo.start();

			this.mix = 0.5;
			this.depth = 0.5;
			this.rate = 0.5;
			this.feedbackLevel = 0.5;
		}

		setMix(value) {
			this.mix = value;
			// Would implement wet/dry mix here
		}

		setDepth(value) {
			this.depth = value;
			this.lfoGain.gain.setValueAtTime(value * 0.02, this.audioCtx.currentTime);
		}

		setRate(value) {
			this.rate = value;
			this.lfo.frequency.setValueAtTime(value, this.audioCtx.currentTime);
		}

		setFeedback(value) {
			this.feedbackLevel = value;
			this.feedback.gain.setValueAtTime(value, this.audioCtx.currentTime);
		}
	}

	// ═══════════════════════════════════════════════════════════════════════════
	// PHASER EFFECT
	// ═══════════════════════════════════════════════════════════════════════════
	class Phaser {
		constructor(audioCtx, destination) {
			this.audioCtx = audioCtx;
			this.destination = destination;

			this.input = audioCtx.createGain();
			this.output = audioCtx.createGain();

			// Allpass filters for phasing
			this.filters = [];
			for (let i = 0; i < 6; i++) {
				const filter = audioCtx.createBiquadFilter();
				filter.type = 'allpass';
				filter.frequency.setValueAtTime(1000 + i * 200, audioCtx.currentTime);
				filter.Q.setValueAtTime(10, audioCtx.currentTime);
				this.filters.push(filter);
			}

			// LFO
			this.lfo = audioCtx.createOscillator();
			this.lfoGain = audioCtx.createGain();
			this.lfo.type = 'sine';
			this.lfo.frequency.setValueAtTime(0.5, audioCtx.currentTime);
			this.lfoGain.gain.setValueAtTime(500, audioCtx.currentTime);

			// Connect LFO to filter frequencies
			this.lfo.connect(this.lfoGain);
			this.filters.forEach(f => this.lfoGain.connect(f.frequency));

			// Connect filters in series
			this.input.connect(this.filters[0]);
			for (let i = 0; i < this.filters.length - 1; i++) {
				this.filters[i].connect(this.filters[i + 1]);
			}
			this.filters[this.filters.length - 1].connect(this.output);
			this.input.connect(this.output);

			this.output.connect(destination);

			this.lfo.start();

			this.mix = 0.5;
			this.rate = 0.5;
			this.depth = 0.5;
			this.stages = 6;
		}

		setRate(value) {
			this.rate = value;
			this.lfo.frequency.setValueAtTime(value * 2, this.audioCtx.currentTime);
		}

		setDepth(value) {
			this.depth = value;
			this.lfoGain.gain.setValueAtTime(value * 1000, this.audioCtx.currentTime);
		}
	}

	// ═══════════════════════════════════════════════════════════════════════════
	// DISTORTION EFFECT
	// ═══════════════════════════════════════════════════════════════════════════
	class DistortionEffect {
		constructor(audioCtx, destination) {
			this.audioCtx = audioCtx;
			this.destination = destination;

			this.input = audioCtx.createGain();
			this.output = audioCtx.createGain();
			this.waveshaper = audioCtx.createWaveShaper();

			this.waveshaper.curve = this.makeCurve(50);
			this.waveshaper.oversample = '4x';

			this.input.connect(this.waveshaper);
			this.waveshaper.connect(this.output);
			this.output.connect(destination);

			this.drive = 50;
			this.tone = 50;
		}

		makeCurve(amount) {
			const samples = 44100;
			const curve = new Float32Array(samples);
			const deg = Math.PI / 180;
			for (let i = 0; i < samples; i++) {
				const x = (i * 2) / samples - 1;
				curve[i] = ((3 + amount) * x * 20 * deg) / (Math.PI + amount * Math.abs(x));
			}
			return curve;
		}

		setDrive(value) {
			this.drive = value;
			this.waveshaper.curve = this.makeCurve(value);
		}

		setTone(value) {
			this.tone = value;
		}
	}

	// ═══════════════════════════════════════════════════════════════════════════
	// COMPRESSOR/LIMITER
	// ═══════════════════════════════════════════════════════════════════════════
	class DynamicsProcessor {
		constructor(audioCtx, destination) {
			this.audioCtx = audioCtx;
			this.destination = destination;

			this.compressor = audioCtx.createDynamicsCompressor();
			this.compressor.threshold.setValueAtTime(-24, audioCtx.currentTime);
			this.compressor.knee.setValueAtTime(30, audioCtx.currentTime);
			this.compressor.ratio.setValueAtTime(12, audioCtx.currentTime);
			this.compressor.attack.setValueAtTime(0.003, audioCtx.currentTime);
			this.compressor.release.setValueAtTime(0.25, audioCtx.currentTime);

			this.compressor.connect(destination);

			this.input = audioCtx.createGain();
			this.input.connect(this.compressor);

			// Makeup gain
			this.makeupGain = audioCtx.createGain();
			this.makeupGain.gain.setValueAtTime(1, audioCtx.currentTime);
			this.makeupGain.connect(this.compressor);

			// For sidechain
			this.sidechainInput = audioCtx.createGain();
		}

		setThreshold(value) {
			this.compressor.threshold.setValueAtTime(value, this.audioCtx.currentTime);
		}

		setKnee(value) {
			this.compressor.knee.setValueAtTime(value, this.audioCtx.currentTime);
		}

		setRatio(value) {
			this.compressor.ratio.setValueAtTime(value, this.audioCtx.currentTime);
		}

		setAttack(value) {
			this.compressor.attack.setValueAtTime(value, this.audioCtx.currentTime);
		}

		setRelease(value) {
			this.compressor.release.setValueAtTime(value, this.audioCtx.currentTime);
		}

		setMakeupGain(value) {
			this.makeupGain.gain.setValueAtTime(value, this.audioCtx.currentTime);
		}

		getInput() {
			return this.input;
		}
	}

	// ═══════════════════════════════════════════════════════════════════════════
	// EQUALIZER - Multi-band EQ
	// ═══════════════════════════════════════════════════════════════════════════
	class Equalizer {
		constructor(audioCtx, destination) {
			this.audioCtx = audioCtx;
			this.destination = destination;

			// Create bands
			this.bands = [];
			const frequencies = [60, 170, 350, 1000, 3500, 7000, 12000, 20000];

			frequencies.forEach((freq, i) => {
				const filter = audioCtx.createBiquadFilter();
				if (i === 0 || i === frequencies.length - 1) {
					filter.type = i === 0 ? 'lowshelf' : 'highshelf';
				} else {
					filter.type = 'peaking';
					filter.Q.setValueAtTime(1, audioCtx.currentTime);
				}
				filter.frequency.setValueAtTime(freq, audioCtx.currentTime);
				filter.gain.setValueAtTime(0, audioCtx.currentTime);

				this.bands.push(filter);
			});

			// Connect in series
			this.input = audioCtx.createGain();
			this.output = audioCtx.createGain();

			this.input.connect(this.bands[0]);
			for (let i = 0; i < this.bands.length - 1; i++) {
				this.bands[i].connect(this.bands[i + 1]);
			}
			this.bands[this.bands.length - 1].connect(this.output);
			this.output.connect(destination);

			this.bandGains = new Array(this.bands.length).fill(0);
		}

		setBandGain(band, gain) {
			if (band < this.bands.length) {
				this.bandGains[band] = gain;
				this.bands[band].gain.setValueAtTime(gain, this.audioCtx.currentTime);
			}
		}

		getInput() {
			return this.input;
		}
	}

	// ═══════════════════════════════════════════════════════════════════════════
	// OSCILLOSCOPE VISUALIZER
	// ═══════════════════════════════════════════════════════════════════════════
	class Oscilloscope {
		constructor(canvas, audioCtx) {
			this.canvas = canvas;
			this.ctx = canvas.getContext('2d');
			this.audioCtx = audioCtx;
			this.analyser = audioCtx.createAnalyser();
			this.analyser.fftSize = 2048;
			this.dataArray = new Float32Array(this.analyser.fftSize);
			this.time = 0;

			// Settings
			this.color = '#00ffff';
			this.backgroundColor = 'rgba(0, 0, 0, 0.5)';
			this.lineWidth = 2;
			this.scale = 1;
			this.trigger = 0.5;
		}

		connect(source) {
			source.connect(this.analyser);
		}

		update() {
			this.analyser.getFloatTimeDomainData(this.dataArray);
			this.time += 0.016;
		}

		draw() {
			const ctx = this.ctx;
			const width = this.canvas.width;
			const height = this.canvas.height;

			// Clear
			ctx.fillStyle = this.backgroundColor;
			ctx.fillRect(0, 0, width, height);

			// Draw grid
			ctx.strokeStyle = '#333';
			ctx.lineWidth = 1;
			for (let i = 0; i < 10; i++) {
				ctx.beginPath();
				ctx.moveTo(0, height * i / 10);
				ctx.lineTo(width, height * i / 10);
				ctx.stroke();
				ctx.beginPath();
				ctx.moveTo(width * i / 10, 0);
				ctx.lineTo(width * i / 10, height);
				ctx.stroke();
			}

			// Draw waveform
			ctx.strokeStyle = this.color;
			ctx.lineWidth = this.lineWidth;
			ctx.shadowColor = this.color;
			ctx.shadowBlur = 10;

			ctx.beginPath();
			const sliceWidth = width / this.dataArray.length;
			let x = 0;

			for (let i = 0; i < this.dataArray.length; i++) {
				const v = this.dataArray[i] * this.scale;
				const y = (v + 1) * height / 2;

				if (i === 0) {
					ctx.moveTo(x, y);
				} else {
					ctx.lineTo(x, y);
				}

				x += sliceWidth;
			}

			ctx.stroke();
			ctx.shadowBlur = 0;
		}
	}

	// ═══════════════════════════════════════════════════════════════════════════
	// CIRCULAR SPECTRUM ANALYZER
	// ═══════════════════════════════════════════════════════════════════════════
	class CircularSpectrum {
		constructor(canvas, audioCtx) {
			this.canvas = canvas;
			this.ctx = canvas.getContext('2d');
			this.audioCtx = audioCtx;
			this.analyser = audioCtx.createAnalyser();
			this.analyser.fftSize = 256;
			this.dataArray = new Uint8Array(this.analyser.frequencyBinCount);
			this.time = 0;

			this.rotation = 0;
			this.bars = 64;
		}

		connect(source) {
			source.connect(this.analyser);
		}

		update() {
			this.analyser.getByteFrequencyData(this.dataArray);
			this.time += 0.016;
			this.rotation += 0.01;
		}

		draw() {
			const ctx = this.ctx;
			const centerX = this.canvas.width / 2;
			const centerY = this.canvas.height / 2;
			const radius = Math.min(centerX, centerY) * 0.3;
			const maxHeight = Math.min(centerX, centerY) * 0.6;

			// Clear
			ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);

			// Draw bars
			for (let i = 0; i < this.bars; i++) {
				const value = this.dataArray[i] / 255;
				const angle = (i / this.bars) * Math.PI * 2 + this.rotation;
				const height = value * maxHeight;

				const x1 = centerX + Math.cos(angle) * radius;
				const y1 = centerY + Math.sin(angle) * radius;
				const x2 = centerX + Math.cos(angle) * (radius + height);
				const y2 = centerY + Math.sin(angle) * (radius + height);

				const hue = (i / this.bars) * 360;
				ctx.strokeStyle = `hsl(${hue}, 100%, 50%)`;
				ctx.lineWidth = 3;
				ctx.shadowColor = `hsl(${hue}, 100%, 50%)`;
				ctx.shadowBlur = 10;

				ctx.beginPath();
				ctx.moveTo(x1, y1);
				ctx.lineTo(x2, y2);
				ctx.stroke();
			}

			// Draw center circle
			ctx.strokeStyle = '#00ffff';
			ctx.lineWidth = 2;
			ctx.beginPath();
			ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
			ctx.stroke();

			ctx.shadowBlur = 0;
		}
	}

	// ═══════════════════════════════════════════════════════════════════════════
	// STARFIELD VISUALIZER
	// ═══════════════════════════════════════════════════════════════════════════
	class Starfield {
		constructor(canvas) {
			this.canvas = canvas;
			this.ctx = canvas.getContext('2d');
			this.stars = [];
			this.time = 0;

			// Initialize stars
			for (let i = 0; i < 500; i++) {
				this.stars.push({
					x: Math.random() * canvas.width,
					y: Math.random() * canvas.height,
					z: Math.random() * canvas.width,
					color: ['#ff00ff', '#00ffff', '#ffff00', '#ffffff'][Math.floor(Math.random() * 4)],
					size: Math.random() * 2 + 1,
				});
			}
		}

		update(beatPulse) {
			this.time += 0.016;

			// Move stars (warp speed effect)
			this.stars.forEach(star => {
				star.z -= 5 + beatPulse * 10;
				if (star.z <= 0) {
					star.z = this.canvas.width;
					star.x = Math.random() * this.canvas.width;
					star.y = Math.random() * this.canvas.height;
				}
			});
		}

		draw() {
			const ctx = this.ctx;

			// Clear with fade
			ctx.fillStyle = 'rgba(5, 0, 15, 0.3)';
			ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

			// Draw stars
			this.stars.forEach(star => {
				const x = (star.x - this.canvas.width / 2) * (this.canvas.width / star.z) + this.canvas.width / 2;
				const y = (star.y - this.canvas.height / 2) * (this.canvas.width / star.z) + this.canvas.height / 2;
				const size = (1 - star.z / this.canvas.width) * star.size * 3;

				if (size > 0 && x > 0 && x < this.canvas.width && y > 0 && y < this.canvas.height) {
					ctx.fillStyle = star.color;
					ctx.shadowColor = star.color;
					ctx.shadowBlur = size * 2;
					ctx.beginPath();
					ctx.arc(x, y, size, 0, Math.PI * 2);
					ctx.fill();
				}
			});

			ctx.shadowBlur = 0;
		}
	}

	// ═══════════════════════════════════════════════════════════════════════════
	// MANDALA PATTERN GENERATOR
	// ═══════════════════════════════════════════════════════════════════════════
	class Mandala {
		constructor(canvas) {
			this.canvas = canvas;
			this.ctx = canvas.getContext('2d');
			this.time = 0;
			this.layers = [];

			// Create layers
			for (let i = 0; i < 5; i++) {
				this.layers.push({
					segments: 6 + i * 2,
					radius: 50 + i * 40,
					rotation: i * 0.1,
					speed: (Math.random() - 0.5) * 0.02,
					color: ['#ff00ff', '#00ffff', '#ffff00', '#00ff88', '#ff6b00'][i],
					alpha: 0.5 - i * 0.08,
				});
			}
		}

		update(beatPulse) {
			this.time += 0.016;

			this.layers.forEach((layer, i) => {
				layer.rotation += layer.speed + beatPulse * 0.1 * (i + 1);
			});
		}

		draw() {
			const ctx = this.ctx;
			const centerX = this.canvas.width / 2;
			const centerY = this.canvas.height / 2;

			// Clear
			ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);

			// Draw each layer
			this.layers.forEach(layer => {
				ctx.strokeStyle = layer.color;
				ctx.globalAlpha = layer.alpha;
				ctx.lineWidth = 2;
				ctx.shadowColor = layer.color;
				ctx.shadowBlur = 10;

				for (let i = 0; i < layer.segments; i++) {
					const angle = (i / layer.segments) * Math.PI * 2 + layer.rotation;

					// Draw shape
					ctx.beginPath();
					for (let j = 0; j <= layer.segments; j++) {
						const a = (j / layer.segments) * Math.PI * 2 + layer.rotation;
						const r = layer.radius * (1 + 0.3 * Math.sin(a * 3 + this.time));
						const x = centerX + Math.cos(a) * r;
						const y = centerY + Math.sin(a) * r;

						if (j === 0) ctx.moveTo(x, y);
						else ctx.lineTo(x, y);
					}
					ctx.closePath();
					ctx.stroke();
				}
			});

			ctx.globalAlpha = 1;
			ctx.shadowBlur = 0;
		}
	}

