	// ═══════════════════════════════════════════════════════════════════════════
	// AUTOMATION SYSTEM
	// ═══════════════════════════════════════════════════════════════════════════
	class Automation {
		constructor() {
			this.automationLanes = [];

			// Create default automation lanes
			for (let i = 0; i < 8; i++) {
				this.automationLanes.push({
					name: `Lane ${i + 1}`,
					target: null,
					points: [],
					enabled: false,
				});
			}
		}

		addPoint(lane, time, value) {
			if (lane < this.automationLanes.length) {
				this.automationLanes[lane].points.push({ time, value });
				this.automationLanes[lane].points.sort((a, b) => a.time - b.time);
			}
		}

		removePoint(lane, index) {
			if (lane < this.automationLanes.length) {
				this.automationLanes[lane].points.splice(index, 1);
			}
		}

		getValue(lane, time) {
			if (lane >= this.automationLanes.length) return 0;

			const points = this.automationLanes[lane].points;
			if (points.length === 0) return 0;
			if (points.length === 1) return points[0].value;

			// Find surrounding points
			for (let i = 0; i < points.length - 1; i++) {
				if (time >= points[i].time && time <= points[i + 1].time) {
					const t = (time - points[i].time) / (points[i + 1].time - points[i].time);
					// Linear interpolation
					return points[i].value + (points[i + 1].value - points[i].value) * t;
				}
			}

			return points[points.length - 1].value;
		}

		clearLane(lane) {
			if (lane < this.automationLanes.length) {
				this.automationLanes[lane].points = [];
			}
		}
	}

