	// ═══════════════════════════════════════════════════════════════════════════
	// RECORDING SYSTEM
	// ═══════════════════════════════════════════════════════════════════════════
	class RecordingSystem {
		constructor(audioCtx) {
			this.audioCtx = audioCtx;
			this.mediaRecorder = null;
			this.recordedChunks = [];
			this.isRecording = false;
			this.startTime = 0;
			this.duration = 0;
		}

		async startRecording(destination) {
			try {
				// Create a MediaStreamDestination
				const dest = this.audioCtx.createMediaStreamDestination();
				destination.connect(dest);

				this.mediaRecorder = new MediaRecorder(dest.stream);
				this.recordedChunks = [];

				this.mediaRecorder.ondataavailable = (e) => {
					if (e.data.size > 0) {
						this.recordedChunks.push(e.data);
					}
				};

				this.mediaRecorder.start(100);
				this.isRecording = true;
				this.startTime = this.audioCtx.currentTime;

				return true;
			} catch (e) {
				console.error('Recording not supported:', e);
				return false;
			}
		}

		stopRecording() {
			if (this.mediaRecorder && this.isRecording) {
				this.mediaRecorder.stop();
				this.isRecording = false;
				this.duration = this.audioCtx.currentTime - this.startTime;
			}
		}

		getBlob() {
			if (this.recordedChunks.length === 0) return null;
			return new Blob(this.recordedChunks, { type: 'audio/webm' });
		}

		downloadRecording(filename = 'rave-session.webm') {
			const blob = this.getBlob();
			if (blob) {
				const url = URL.createObjectURL(blob);
				const a = document.createElement('a');
				a.href = url;
				a.download = filename;
				a.click();
				URL.revokeObjectURL(url);
			}
		}
	}

