	// KEY DETECTOR
	// ═══════════════════════════════════════════════════════════════════════════
	class KeyDetector {
		constructor() {
			this.key = 'C';
			this.mode = 'major';

			this.keys = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];
			this.modes = ['major', 'minor'];

			// Note to frequency mapping (A4 = 440Hz)
			this.noteFreqs = {};
			for (let i = 0; i < 128; i++) {
				this.noteFreqs[i] = 440 * Math.pow(2, (i - 69) / 12);
			}
		}

		detectFromPitch(frequency) {
			// Convert frequency to MIDI note
			const note = Math.round(12 * Math.log2(frequency / 440) + 69);
			const noteName = this.keys[note % 12];
			const octave = Math.floor(note / 12) - 1;

			return { note, noteName, octave, frequency };
		}

		setKey(key) {
			if (this.keys.includes(key)) {
				this.key = key;
			}
		}

		setMode(mode) {
			if (this.modes.includes(mode)) {
				this.mode = mode;
			}
		}

		getKeyDisplay() {
			return `${this.key} ${this.mode === 'major' ? 'Maj' : 'Min'}`;
		}
	}

	// ═══════════════════════════════════════════════════════════════════════════
	// BEAT DETECTOR
	// ═══════════════════════════════════════════════════════════════════════════
	class BeatDetector {
		constructor(audioCtx) {
			this.audioCtx = audioCtx;
			this.analyser = audioCtx.createAnalyser();
			this.analyser.fftSize = 2048;
			this.dataArray = new Float32Array(this.analyser.frequencyBinCount);

			this.threshold = 0.6;
			this.minInterval = 0.2; // Minimum 200ms between beats
			this.lastBeatTime = 0;
			this.bpm = 120;
			this.beatCount = 0;

			this.beatHistory = [];
		}

		connect(source) {
			source.connect(this.analyser);
		}

		process() {
			this.analyser.getFloatTimeDomainData(this.dataArray);

			// Calculate RMS
			let sum = 0;
			for (let i = 0; i < this.dataArray.length; i++) {
				sum += this.dataArray[i] * this.dataArray[i];
			}
			const rms = Math.sqrt(sum / this.dataArray.length);

			// Beat detection
			const now = this.audioCtx.currentTime;

			if (rms > this.threshold && (now - this.lastBeatTime) > this.minInterval) {
				this.lastBeatTime = now;
				this.beatCount++;

				// Add to history for BPM calculation
				this.beatHistory.push(now);
				if (this.beatHistory.length > 20) {
					this.beatHistory.shift();
				}

				// Calculate BPM from history
				if (this.beatHistory.length >= 4) {
					const intervals = [];
					for (let i = 1; i < this.beatHistory.length; i++) {
						intervals.push(this.beatHistory[i] - this.beatHistory[i - 1]);
					}
					const avgInterval = intervals.reduce((a, b) => a + b, 0) / intervals.length;
					this.bpm = Math.round(60 / avgInterval);
				}

				return true;
			}

			return false;
		}

		setThreshold(value) {
			this.threshold = value;
		}

		setMinInterval(value) {
			this.minInterval = value;
		}

		getBPM() {
			return this.bpm;
		}
	}

	// ═══════════════════════════════════════════════════════════════════════════
	// LOOP MANAGER
	// ═══════════════════════════════════════════════════════════════════════════
	class LoopManager {
		constructor() {
			this.loops = [];
			this.activeLoop = null;

			// Predefined loop lengths in beats
			this.loopLengths = [0.25, 0.5, 1, 2, 4, 8, 16, 32];

			// Create 8 loop slots
			for (let i = 0; i < 8; i++) {
				this.loops.push({
					active: false,
					start: 0,
					length: 4,
					hotcue: null,
				});
			}
		}

		setLoop(slot, start, length) {
			if (slot < this.loops.length) {
				this.loops[slot].start = start;
				this.loops[slot].length = length;
			}
		}

		activateLoop(slot) {
			if (slot < this.loops.length) {
				this.loops.forEach(l => l.active = false);
				this.loops[slot].active = true;
				this.activeLoop = slot;
			}
		}

		deactivateLoop(slot) {
			if (slot < this.loops.length) {
				this.loops[slot].active = false;
				if (this.activeLoop === slot) {
					this.activeLoop = null;
				}
			}
		}

		toggleLoop(slot) {
			if (this.loops[slot].active) {
				this.deactivateLoop(slot);
			} else {
				this.activateLoop(slot);
			}
		}

		getActiveLoop() {
			return this.activeLoop !== null ? this.loops[this.activeLoop] : null;
		}
	}

