	// HOT CUE MANAGER
	// ═══════════════════════════════════════════════════════════════════════════
	class HotCueManager {
		constructor() {
			this.hotCues = [];

			// Create 8 hot cue slots
			for (let i = 0; i < 8; i++) {
				this.hotCues.push({
					active: false,
					time: 0,
					color: ['#ff0044', '#ff8800', '#ffff00', '#00ff88', '#00ffff', '#0088ff', '#8800ff', '#ff00ff'][i],
					name: `Cue ${i + 1}`,
				});
			}
		}

		setCue(slot, time, name = null) {
			if (slot < this.hotCues.length) {
				this.hotCues[slot].active = true;
				this.hotCues[slot].time = time;
				if (name) this.hotCues[slot].name = name;
			}
		}

		clearCue(slot) {
			if (slot < this.hotCues.length) {
				this.hotCues[slot].active = false;
				this.hotCues[slot].time = 0;
			}
		}

		getCue(slot) {
			return slot < this.hotCues.length ? this.hotCues[slot] : null;
		}

		jumpToCue(slot) {
			if (slot < this.hotCues.length && this.hotCues[slot].active) {
				return this.hotCues[slot].time;
			}
			return null;
		}
	}

